import React from "react"


class AddUser extends React.Component {
    addUser = {}
    constructor(props) {
        super(props)
        this.state = {
            firstname: "",
            info: "",
            job: ""
        }
    }
    render() {
        return (<form className="add-user-form" ref={(item) => this.addForm = item}>
            <input placeholder="Имя" onChange={(e) => this.setState({firstname: e.target.value})} />
            <textarea placeholder="Информация о себе" onChange={(e) => this.setState({info: e.target.value})} />
            <input placeholder="Профессия" onChange={(e) => this.setState({job: e.target.value})} />

            <button type="button" onClick={() => {
                this.addForm.reset()
